class Solution(object):
    def minOperations(self, s):
        pattern1 = sum(1 for i, c in enumerate(s) if int(c) != i % 2)
        pattern2 = sum(1 for i, c in enumerate(s) if int(c) != (i + 1) % 2)
        return min(pattern1, pattern2)
